import logo from "./FinTrack-Logo.png";
import "./Navbar.css";
import { NavLink } from "react-router-dom";


function Navbar() {
  return (
    <nav className="navbar">
      <div className="elements">

        <div className="logo">
          <img src={logo} alt="FinTrack Logo" className="logo" />
        </div>

        <NavLink
          to="/dashboard"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Dashboard
        </NavLink>

        <NavLink
          to="/transactions"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Transactions
        </NavLink>

        <NavLink
          to="/analytics"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Analytics
        </NavLink>

      </div>
    </nav>
  );
}

export default Navbar;
